                            let jsval_eq_func = extern_funcs.get("js_jsvalue_equals")
                                .ok_or_else(|| anyhow!("js_jsvalue_equals not declared"))?;
                            let jsval_eq_ref = module.declare_func_in_func(*jsval_eq_func, builder.func);
