                        let is_zero = builder.ins().icmp(IntCC::Equal, rhs, zero_i64);
                        let nanboxed = inline_nanbox_pointer(builder, rhs);
                        let undef_bits = builder.ins().iconst(types::I64, 0x7FFC_0000_0000_0001u64 as i64);
