                            let box_get_func = extern_funcs.get("js_box_get")
                                .ok_or_else(|| anyhow!("js_box_get not declared"))?;
                            let box_get_ref = module.declare_func_in_func(*box_get_func, builder.func);
                            let call = builder.ins().call(box_get_ref, &[box_ptr]);
