                    let this_f64 = builder.ins().bitcast(types::F64, MemFlags::new(), this_ptr);
                    // Store at index 0
                    let idx = builder.ins().iconst(types::I32, 0);
                    builder.ins().call(set_ref, &[closure_ptr, idx, this_f64]);
