                        let null_ptr = builder.ins().iconst(types::I64, 0);
                        let null_f64 = builder.ins().bitcast(types::F64, MemFlags::new(), null_ptr);
                        let idx = builder.ins().iconst(types::I32, 0);
                        builder.ins().call(set_ref, &[closure_ptr, idx, null_f64]);
