                let nanbox_string_func = extern_funcs.get("js_nanbox_string")
                    .ok_or_else(|| anyhow!("js_nanbox_string not declared"))?;
                let nanbox_string_ref = module.declare_func_in_func(*nanbox_string_func, builder.func);

